#include <stdio.h>
#include <string.h>

// Helper to mimic Python slicing for a given step (positive or negative)
void slice(const char *src, int start, int end, int step, char *dest) {
    int len = strlen(src);
    // Convert negative indices
    if (start < 0) start = len + start;
    if (end < 0) end = len + end;
    // Clamp to bounds
    if (step > 0) {
        if (start < 0) start = 0;
        if (end > len) end = len;
    } else {
        if (start >= len) start = len - 1;
        if (end < -1) end = -1;
    }
    int pos = 0;
    if (step > 0) {
        for (int i = start; i < end; i += step) {
            dest[pos++] = src[i];
        }
    } else {
        for (int i = start; i > end; i += step) {
            dest[pos++] = src[i];
        }
    }
    dest[pos] = '\0';
}

int main() {
    const char url[] = "www.example.com/home";
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int sd, ed, stepd, st, et, stept, sp, ep, stepp;
        scanf("%d %d %d %d %d %d %d %d %d", &sd, &ed, &stepd, &st, &et, &stept, &sp, &ep, &stepp);
        char domain[30], tld[30], path[30];
        slice(url, sd, ed, stepd, domain);
        slice(url, st, et, stept, tld);
        slice(url, sp, ep, stepp, path);
        if (T) printf("\n");
        printf("Extracted Parts of the URL:\n");
        printf("Domain Name: %s\n", domain);
        printf("Top-Level Domain (TLD): %s\n", tld);
        printf("Path/Extension: %s\n", path);
    }
    return 0;
}

