#include <bits/stdc++.h>
using namespace std;

string slice(const string &s, int start, int end, int step) {
    int n = (int)s.size();
    if (start < 0) start += n;
    if (end < 0) end += n;
    string res;
    if (step > 0) {
        for (int i = start; i < end && i < n; i += step) res.push_back(s[i]);
    } else {
        for (int i = start; i > end && i >= 0; i += step) res.push_back(s[i]);
    }
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    const string url = "www.example.com/home";
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int sd, ed, stepd, st, et, stept, sp, ep, stepp;
        cin >> sd >> ed >> stepd >> st >> et >> stept >> sp >> ep >> stepp;
        string domain = slice(url, sd, ed, stepd);
        string tld = slice(url, st, et, stept);
        string path = slice(url, sp, ep, stepp);
        if (T) cout << '\n';
        cout << "Extracted Parts of the URL:" << '\n';
        cout << "Domain Name: " << domain << '\n';
        cout << "Top-Level Domain (TLD): " << tld << '\n';
        cout << "Path/Extension: " << path << '\n';
    }
    return 0;
}

