import java.io.*;
import java.util.*;

public class Main {
    private static String slice(String s, int start, int end, int step) {
        int n = s.length();
        if (start < 0) start += n;
        if (end < 0) end += n;
        StringBuilder sb = new StringBuilder();
        if (step > 0) {
            for (int i = start; i < end && i < n; i += step) sb.append(s.charAt(i));
        } else {
            for (int i = start; i > end && i >= 0; i += step) sb.append(s.charAt(i));
        }
        return sb.toString();
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        String url = "www.example.com/home";
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int[] vals = new int[9];
            for (int i = 0; i < 9; i++) {
                vals[i] = Integer.parseInt(br.readLine().trim());
            }
            String domain = slice(url, vals[0], vals[1], vals[2]);
            String tld = slice(url, vals[3], vals[4], vals[5]);
            String path = slice(url, vals[6], vals[7], vals[8]);
            if (tc > 0) out.append('\n');
            out.append("Extracted Parts of the URL:\n");
            out.append("Domain Name: ").append(domain).append('\n');
            out.append("Top-Level Domain (TLD): ").append(tld).append('\n');
            out.append("Path/Extension: ").append(path).append('\n');
        }
        System.out.print(out.toString());
    }
}

